@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";

@custom-variant dark (&:is(.dark *));

@theme inline {
    --font-heading: var(--font-sans);
    --font-sans: var(--font-sans);
    --font-orbitron: var(--font-orbitron);
    --font-space-mono: var(--font-space-mono);
    --font-noto-serif-jp: var(--font-noto-serif-jp);
    --color-background-warm: var(--background-warm);
    --color-gold: var(--gold);
    --color-gold-dim: var(--gold-dim);
    --color-teal: var(--teal);
    --color-sidebar-ring: var(--sidebar-ring);
    --color-sidebar-border: var(--sidebar-border);
    --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
    --color-sidebar-accent: var(--sidebar-accent);
    --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
    --color-sidebar-primary: var(--sidebar-primary);
    --color-sidebar-foreground: var(--sidebar-foreground);
    --color-sidebar: var(--sidebar);
    --color-chart-5: var(--chart-5);
    --color-chart-4: var(--chart-4);
    --color-chart-3: var(--chart-3);
    --color-chart-2: var(--chart-2);
    --color-chart-1: var(--chart-1);
    --color-ring: var(--ring);
    --color-input: var(--input);
    --color-border: var(--border);
    --color-destructive: var(--destructive);
    --color-accent-foreground: var(--accent-foreground);
    --color-accent: var(--accent);
    --color-muted-foreground: var(--muted-foreground);
    --color-muted: var(--muted);
    --color-secondary-foreground: var(--secondary-foreground);
    --color-secondary: var(--secondary);
    --color-primary-foreground: var(--primary-foreground);
    --color-primary: var(--primary);
    --color-popover-foreground: var(--popover-foreground);
    --color-popover: var(--popover);
    --color-card-foreground: var(--card-foreground);
    --color-card: var(--card);
    --color-foreground: var(--foreground);
    --color-background: var(--background);
    --radius-sm: calc(var(--radius) * 0.6);
    --radius-md: calc(var(--radius) * 0.8);
    --radius-lg: var(--radius);
    --radius-xl: calc(var(--radius) * 1.4);
    --radius-2xl: calc(var(--radius) * 1.8);
    --radius-3xl: calc(var(--radius) * 2.2);
    --radius-4xl: calc(var(--radius) * 2.6);
}

:root {
    /* JukuBox.ai — Warm Retro Chic */
    /* システム共通デザイントークン（shadcn 変数を上書き） */
    --background: oklch(0.10 0.015 50);
    --foreground: oklch(0.90 0.03 78);
    --card: oklch(0.17 0.02 50 / 0.9);
    --card-foreground: oklch(0.90 0.03 78);
    --popover: oklch(0.17 0.02 50 / 0.9);
    --popover-foreground: oklch(0.90 0.03 78);
    --muted-foreground: oklch(0.72 0.025 55);
    --border: oklch(1 0 0 / 0.15);
    --input: oklch(1 0 0 / 0.07);
    /* shadcn に対応がないシステム共通トークン */
    --background-warm: oklch(0.13 0.02 50);
    --gold: oklch(0.75 0.12 77);
    --gold-dim: oklch(0.50 0.08 77);
    --teal: oklch(0.72 0.09 190);
    --grid-line: oklch(0.75 0.12 77 / 0.04);
    --primary: oklch(0.205 0 0);
    --primary-foreground: oklch(0.985 0 0);
    --secondary: oklch(0.97 0 0);
    --secondary-foreground: oklch(0.205 0 0);
    --muted: oklch(0.269 0 0);
    --accent: oklch(0.269 0 0);
    --accent-foreground: oklch(0.985 0 0);
    --destructive: oklch(0.577 0.245 27.325);
    --ring: oklch(0.708 0 0);
    --chart-1: oklch(0.87 0 0);
    --chart-2: oklch(0.556 0 0);
    --chart-3: oklch(0.439 0 0);
    --chart-4: oklch(0.371 0 0);
    --chart-5: oklch(0.269 0 0);
    --radius: 0.625rem;
    --sidebar: oklch(0.985 0 0);
    --sidebar-foreground: oklch(0.145 0 0);
    --sidebar-primary: oklch(0.205 0 0);
    --sidebar-primary-foreground: oklch(0.985 0 0);
    --sidebar-accent: oklch(0.97 0 0);
    --sidebar-accent-foreground: oklch(0.205 0 0);
    --sidebar-border: oklch(0.922 0 0);
    --sidebar-ring: oklch(0.708 0 0);
}

.dark {
    --background: oklch(0.145 0 0);
    --foreground: oklch(0.985 0 0);
    --card: oklch(0.205 0 0);
    --card-foreground: oklch(0.985 0 0);
    --popover: oklch(0.205 0 0);
    --popover-foreground: oklch(0.985 0 0);
    --primary: oklch(0.922 0 0);
    --primary-foreground: oklch(0.205 0 0);
    --secondary: oklch(0.269 0 0);
    --secondary-foreground: oklch(0.985 0 0);
    --muted: oklch(0.269 0 0);
    --muted-foreground: oklch(0.708 0 0);
    --accent: oklch(0.269 0 0);
    --accent-foreground: oklch(0.985 0 0);
    --destructive: oklch(0.704 0.191 22.216);
    --border: oklch(1 0 0 / 10%);
    --input: oklch(1 0 0 / 15%);
    --ring: oklch(0.556 0 0);
    --chart-1: oklch(0.87 0 0);
    --chart-2: oklch(0.556 0 0);
    --chart-3: oklch(0.439 0 0);
    --chart-4: oklch(0.371 0 0);
    --chart-5: oklch(0.269 0 0);
    --sidebar: oklch(0.205 0 0);
    --sidebar-foreground: oklch(0.985 0 0);
    --sidebar-primary: oklch(0.488 0.243 264.376);
    --sidebar-primary-foreground: oklch(0.985 0 0);
    --sidebar-accent: oklch(0.269 0 0);
    --sidebar-accent-foreground: oklch(0.985 0 0);
    --sidebar-border: oklch(1 0 0 / 10%);
    --sidebar-ring: oklch(0.556 0 0);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
    }
  body {
    @apply bg-background text-foreground;
    }
  html {
    @apply font-sans;
    }
}

/* ===== JukuBox.ai ランディングページ用スタイル ===== */

/* フィルムグレイン質感 */
body::after {
  content: '';
  position: fixed;
  inset: 0;
  background-image: url("data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' width='200' height='200'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/><feColorMatrix type='saturate' values='0'/></filter><rect width='200' height='200' filter='url(%23n)' opacity='0.18'/></svg>");
  opacity: 0.055;
  pointer-events: none;
  z-index: 9000;
  mix-blend-mode: overlay;
}

@keyframes juku-record-spin {
  from { transform: rotate(0deg); }
  to { transform: rotate(360deg); }
}

@keyframes juku-breathe {
  0%, 100% { opacity: 0.85; }
  50% { opacity: 1; }
}

@keyframes juku-glow-gold {
  0%, 100% {
    box-shadow: 0 0 8px var(--gold-dim), 0 0 16px oklch(0.75 0.12 77 / 0.2);
  }
  50% {
    box-shadow: 0 0 12px var(--gold), 0 0 28px oklch(0.75 0.12 77 / 0.25);
  }
}

.juku-glow-gold-text {
  text-shadow: 0 0 18px oklch(0.75 0.12 77 / 0.45);
}

.juku-glass {
  background: var(--card);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border: 1px solid oklch(1 0 0 / 0.18);
}

.juku-grid-bg {
  background-image:
    linear-gradient(var(--grid-line) 1px, transparent 1px),
    linear-gradient(90deg, var(--grid-line) 1px, transparent 1px);
  background-size: 48px 48px;
}

.juku-record-spin {
  animation: juku-record-spin 32s linear infinite;
}

.juku-breathe {
  animation: juku-breathe 4s ease-in-out infinite;
}

.juku-glow-border {
  animation: juku-glow-gold 4s ease-in-out infinite;
}

.juku-cta-btn-primary {
  position: relative;
  background: transparent;
  border: 1px solid var(--gold);
  color: var(--gold);
  transition: all 0.35s ease;
  overflow: hidden;
  cursor: pointer;
}

.juku-cta-btn-primary::before {
  content: '';
  position: absolute;
  inset: 0;
  background: var(--gold);
  transform: scaleX(0);
  transform-origin: left;
  transition: transform 0.35s ease;
  z-index: 0;
}

.juku-cta-btn-primary:hover::before {
  transform: scaleX(1);
}

.juku-cta-btn-primary:hover {
  color: var(--background);
  box-shadow: 0 0 16px oklch(0.75 0.12 77 / 0.3);
}

.juku-cta-btn-primary span {
  position: relative;
  z-index: 1;
}

.juku-cta-btn-secondary {
  position: relative;
  background: transparent;
  border: 1px solid oklch(1 0 0 / 0.2);
  color: var(--muted-foreground);
  transition: all 0.3s ease;
  cursor: pointer;
}

.juku-cta-btn-secondary:hover {
  border-color: oklch(1 0 0 / 0.45);
  color: var(--foreground);
}

.juku-feature-card {
  position: relative;
  overflow: hidden;
  transition: all 0.4s ease;
}

.juku-feature-card::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--gold-dim), transparent);
}

.juku-feature-card:hover {
  transform: translateY(-3px);
  border-color: oklch(1 0 0 / 0.12);
}

.juku-divider {
  width: 100%;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--gold-dim) 30%, var(--gold-dim) 70%, transparent);
  opacity: 0.5;
}

export function Nav() {
  return (
    <nav
      className="fixed top-0 left-0 right-0 z-50 flex items-center justify-between px-8 py-4"
      style={{
        background: "oklch(0.10 0.015 50 / 0.92)",
        backdropFilter: "blur(24px)",
        WebkitBackdropFilter: "blur(24px)",
        borderBottom: "1px solid oklch(0.75 0.12 77 / 0.1)",
      }}
    >
      {/* ロゴ */}
      <a href="#" className="flex items-baseline gap-0.5 no-underline">
        <span
          className="font-orbitron font-black text-xl tracking-wider juku-glow-gold-text"
          style={{ color: "var(--gold)" }}
        >
          JukuBox
        </span>
        <span
          className="font-orbitron font-bold text-sm"
          style={{ color: "var(--teal)" }}
        >
          .ai
        </span>
      </a>

      {/* ナビリンク */}
      <div className="hidden md:flex items-center gap-8">
        {["機能", "使い方", "学習記録"].map((label) => (
          <a
            key={label}
            href={`#${label}`}
            className="text-sm tracking-wide transition-colors duration-200"
            style={{ color: "var(--muted-foreground)" }}
          >
            {label}
          </a>
        ))}
      </div>

      {/* CTA */}
      <button className="juku-cta-btn-primary px-5 py-2 text-xs font-orbitron font-bold uppercase tracking-widest">
        <span>無料で始める</span>
      </button>
    </nav>
  );
}

function VinylRecord() {
  const grooves = Array.from({ length: 26 }, (_, i) => i);
  return (
    <svg
      viewBox="0 0 400 400"
      xmlns="http://www.w3.org/2000/svg"
      className="w-full h-full"
    >
      {/* ベース */}
      <circle cx="200" cy="200" r="195" fill="oklch(0.12 0.02 50)" />
      {/* 外縁ハイライト */}
      <circle cx="200" cy="200" r="194" fill="none" stroke="oklch(0.75 0.12 77 / 0.28)" strokeWidth="1" />
      {/* 溝 */}
      {grooves.map((i) => (
        <circle
          key={i}
          cx="200"
          cy="200"
          r={180 - i * 5}
          fill="none"
          stroke={
            i % 4 === 0
              ? "oklch(0.75 0.12 77 / 0.22)"
              : "oklch(0.75 0.12 77 / 0.08)"
          }
          strokeWidth={i % 4 === 0 ? "0.8" : "0.4"}
        />
      ))}
      {/* センターラベルエリア */}
      <circle cx="200" cy="200" r="60" fill="oklch(0.20 0.03 55)" />
      <circle cx="200" cy="200" r="57" fill="none" stroke="oklch(0.75 0.12 77 / 0.55)" strokeWidth="0.8" />
      <circle cx="200" cy="200" r="52" fill="none" stroke="oklch(0.75 0.12 77 / 0.28)" strokeWidth="0.4" />
      {/* ラベルテキスト */}
      <text
        x="200"
        y="196"
        textAnchor="middle"
        fontSize="10"
        fontFamily="Orbitron, sans-serif"
        fontWeight="700"
        fill="oklch(0.75 0.12 77)"
        letterSpacing="2.5"
      >
        JUKUBOX
      </text>
      <text
        x="200"
        y="211"
        textAnchor="middle"
        fontSize="7"
        fontFamily="Space Mono, monospace"
        fill="oklch(0.72 0.09 190)"
        letterSpacing="1.5"
      >
        .AI
      </text>
      {/* センターホール */}
      <circle cx="200" cy="200" r="7" fill="oklch(0.09 0.015 50)" />
      {/* 反射ハイライト（斜め） */}
      <path
        d="M 90 120 A 130 130 0 0 1 240 65"
        fill="none"
        stroke="oklch(0.75 0.12 77 / 0.40)"
        strokeWidth="1.5"
        strokeLinecap="round"
      />
    </svg>
  );
}

export function Hero() {
  return (
    <section
      className="relative min-h-screen flex items-center overflow-hidden juku-grid-bg"
      style={{ background: "var(--background)" }}
    >
      {/* 背景ラジアルグロウ（控えめ） */}
      <div
        className="absolute inset-0 pointer-events-none"
        style={{
          background:
            "radial-gradient(ellipse 55% 45% at 68% 50%, oklch(0.75 0.12 77 / 0.04) 0%, transparent 65%)",
        }}
      />

      <div className="relative z-10 w-full max-w-7xl mx-auto px-8 pt-24 pb-16 flex flex-col lg:flex-row items-center gap-16 lg:gap-0">
        {/* 左: テキスト */}
        <div className="flex-1 flex flex-col gap-7 lg:pr-16">
          {/* 小ラベル */}
          <div
            className="flex items-center gap-3"
            style={{ color: "var(--muted-foreground)" }}
          >
            <div
              className="w-8 h-px"
              style={{ background: "var(--gold-dim)" }}
            />
            <span className="font-space-mono text-xs uppercase tracking-[0.25em]">
              AI Learning Platform
            </span>
          </div>

          {/* ロゴ */}
          <h1 className="flex flex-col gap-0">
            <span
              className="font-orbitron font-black leading-none text-7xl lg:text-8xl juku-glow-gold-text"
              style={{ color: "var(--gold)" }}
            >
              JukuBox
            </span>
            <span
              className="font-orbitron font-bold leading-none text-4xl lg:text-5xl"
              style={{ color: "var(--teal)" }}
            >
              .ai
            </span>
          </h1>

          {/* キャッチコピー（明朝体） */}
          <p
            className="font-noto-serif-jp font-bold text-2xl lg:text-3xl leading-relaxed"
            style={{ color: "var(--foreground)" }}
          >
            AI エージェントと
            <br />
            好きなことを好きなだけ学ぶ
          </p>

          {/* 説明 */}
          <p
            className="text-base leading-loose max-w-lg"
            style={{ color: "var(--muted-foreground)" }}
          >
            自分が契約している AI エージェントをそのまま活用。
            コースを選んで学ぶも良し、自分で作るも良し。
            記録が積み重なるほど、学びは深くなる。
          </p>

          {/* ボタン */}
          <div className="flex flex-wrap items-center gap-4 mt-1">
            <button className="juku-cta-btn-primary px-8 py-3.5 font-orbitron font-bold text-sm uppercase tracking-widest">
              <span>無料で始める →</span>
            </button>
            <button className="juku-cta-btn-secondary px-8 py-3.5 font-orbitron font-bold text-sm uppercase tracking-widest">
              デモを見る
            </button>
          </div>

          {/* 対応AIモデル */}
          <div
            className="flex items-center gap-2 mt-2"
            style={{ color: "var(--muted-foreground)" }}
          >
            <span className="font-space-mono text-xs">対応:</span>
            {["Claude", "GPT-4o", "Gemini", "Llama"].map((m) => (
              <span
                key={m}
                className="font-space-mono text-xs px-2 py-0.5"
                style={{
                  border: "1px solid var(--border)",
                  color: "oklch(0.75 0.04 55)",
                }}
              >
                {m}
              </span>
            ))}
          </div>
        </div>

        {/* 右: ビニールレコード */}
